package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVPrinterTest {

    @Mock
    private Appendable out;

    @Mock
    private CSVFormat format;

    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrint_nullValue_nullStringNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        // Use reflection to spy on private print(Object, String, int, int)
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, String.class, int.class, int.class);
        printMethod.setAccessible(true);

        CSVPrinter spyPrinter = spy(printer);

        // Do nothing on private print to avoid IOException for this test
        doNothing().when(spyPrinter).print(any(), anyString(), anyInt(), anyInt());

        spyPrinter.print(null);

        verify(format).getNullString();
        verify(spyPrinter).print(null, "", 0, 0);
    }

    @Test
    void testPrint_nullValue_nullStringNotNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        String nullString = "NULL";
        when(format.getNullString()).thenReturn(nullString);

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, String.class, int.class, int.class);
        printMethod.setAccessible(true);

        CSVPrinter spyPrinter = spy(printer);
        doNothing().when(spyPrinter).print(any(), anyString(), anyInt(), anyInt());

        spyPrinter.print(null);

        verify(format).getNullString();
        verify(spyPrinter).print(null, nullString, 0, nullString.length());
    }

    @Test
    void testPrint_nonNullValue() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        String value = "testValue";

        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, String.class, int.class, int.class);
        printMethod.setAccessible(true);

        CSVPrinter spyPrinter = spy(printer);
        doNothing().when(spyPrinter).print(any(), anyString(), anyInt(), anyInt());

        spyPrinter.print(value);

        verify(format, never()).getNullString();
        verify(spyPrinter).print(value, value, 0, value.length());
    }
}
